import weaviate
from weaviate.classes.query import MetadataQuery

# Indexer subagent: batch-insert documents and cross-references
documents = client.collections.get("Document")
with documents.batch.dynamic() as batch:
    for doc in document_batch:
        uuid = batch.add_object(
            properties={
                "text": doc["text"],
                "source": doc["source"],
            },
            vector=doc["embedding"],
        )
        # Store uuid for later cross-reference linking

# Retriever subagent: execute hybrid queries
response = documents.query.hybrid(
    query=user_query,
    vector=query_embedding,
    alpha=0.6,
    limit=10,
    return_metadata=MetadataQuery(score=True)
)

# Graph-enricher subagent: traverse cross-references
enriched_results = []
for obj in response.objects:
    result = client.graphql_raw_query(f"""
    {{
      Get {{
        Document(
          where: {{path: ["_id"], operator: Equal, valueString: "{obj.uuid}"}}
          limit: 1
        ) {{
          text source
          hasAuthor {{ ... on Author {{ name email }} }}
          _additional {{ certainty }}
        }}
      }}
    }}
    """)
    enriched_results.append(result)

# Generator subagent: synthesize grounded answer from enriched results
